#ifndef KERNEL_H
#define KERNEL_H

#include <ap_int.h>
#include <ap_fixed.h>
#include <hls_math.h>

// Project configuration from py2c.yaml and project.yaml
#define MATRIX_SIZE 10
#define TOTAL_BITS 46
#define FRAC_BITS 14
#define MAX_ITERATIONS 2000
#define CONVERGENCE_THRESHOLD 164  // 1e-8 scaled to Q14 format (approx 0.00001 in Q14)

// Fixed-point type: 46 bits total, 14 fractional bits
// This gives us 32 integer bits (including sign)
typedef ap_fixed<TOTAL_BITS, TOTAL_BITS - FRAC_BITS, AP_RND, AP_SAT> fixed_t;

// Complex number structure
struct complex_t {
    fixed_t re;
    fixed_t im;

    complex_t() : re(0), im(0) {}
    complex_t(fixed_t r, fixed_t i) : re(r), im(i) {}
};

// Complex arithmetic helper functions
inline complex_t complex_add(const complex_t& a, const complex_t& b) {
    return complex_t(a.re + b.re, a.im + b.im);
}

inline complex_t complex_sub(const complex_t& a, const complex_t& b) {
    return complex_t(a.re - b.re, a.im - b.im);
}

inline complex_t complex_mul(const complex_t& a, const complex_t& b) {
    fixed_t re = a.re * b.re - a.im * b.im;
    fixed_t im = a.re * b.im + a.im * b.re;
    return complex_t(re, im);
}

inline complex_t complex_conj(const complex_t& a) {
    return complex_t(a.re, -a.im);
}

inline fixed_t complex_abs(const complex_t& a) {
    // |z| = sqrt(re^2 + im^2)
    fixed_t re_sq = a.re * a.re;
    fixed_t im_sq = a.im * a.im;
    fixed_t sum = re_sq + im_sq;
    return hls::sqrt(sum);
}

inline fixed_t complex_angle(const complex_t& a) {
    // atan2(im, re)
    return hls::atan2(a.im, a.re);
}

// Top-level kernel function
void kernel_top(
    const ap_int<TOTAL_BITS> matrix_real_in[MATRIX_SIZE * MATRIX_SIZE],
    const ap_int<TOTAL_BITS> matrix_imag_in[MATRIX_SIZE * MATRIX_SIZE],
    ap_int<TOTAL_BITS> eigenvalues_real_out[MATRIX_SIZE],
    ap_int<TOTAL_BITS> eigenvectors_real_out[MATRIX_SIZE * MATRIX_SIZE],
    ap_int<TOTAL_BITS> eigenvectors_imag_out[MATRIX_SIZE * MATRIX_SIZE],
    ap_uint<12>& iter_count,
    ap_uint<32>& cycles
);

#endif // KERNEL_H

#include "kernel.h"
#include <hls_stream.h>

// Convert ap_int to fixed_t
static fixed_t int_to_fixed(ap_int<TOTAL_BITS> val) {
    fixed_t result;
    result.range() = val.range(TOTAL_BITS-1, 0);
    return result;
}

// Convert fixed_t to ap_int
static ap_int<TOTAL_BITS> fixed_to_int(fixed_t val) {
    ap_int<TOTAL_BITS> result;
    result.range(TOTAL_BITS-1, 0) = val.range();
    return result;
}

// Jacobi eigenvalue decomposition kernel
void kernel_top(
    const ap_int<TOTAL_BITS> matrix_real_in[MATRIX_SIZE * MATRIX_SIZE],
    const ap_int<TOTAL_BITS> matrix_imag_in[MATRIX_SIZE * MATRIX_SIZE],
    ap_int<TOTAL_BITS> eigenvalues_real_out[MATRIX_SIZE],
    ap_int<TOTAL_BITS> eigenvectors_real_out[MATRIX_SIZE * MATRIX_SIZE],
    ap_int<TOTAL_BITS> eigenvectors_imag_out[MATRIX_SIZE * MATRIX_SIZE],
    ap_uint<12>& iter_count,
    ap_uint<32>& cycles
) {
    // Interface pragmas
    #pragma HLS INTERFACE mode=m_axi port=matrix_real_in bundle=gmem0 depth=100
    #pragma HLS INTERFACE mode=m_axi port=matrix_imag_in bundle=gmem1 depth=100
    #pragma HLS INTERFACE mode=m_axi port=eigenvalues_real_out bundle=gmem2 depth=10
    #pragma HLS INTERFACE mode=m_axi port=eigenvectors_real_out bundle=gmem3 depth=100
    #pragma HLS INTERFACE mode=m_axi port=eigenvectors_imag_out bundle=gmem4 depth=100
    #pragma HLS INTERFACE mode=s_axilite port=iter_count
    #pragma HLS INTERFACE mode=s_axilite port=cycles
    #pragma HLS INTERFACE mode=s_axilite port=return

    // Local matrix A (working copy)
    complex_t A[MATRIX_SIZE][MATRIX_SIZE];
    #pragma HLS ARRAY_PARTITION variable=A dim=0 type=complete

    // Local eigenvector matrix V (initialized to identity)
    complex_t V[MATRIX_SIZE][MATRIX_SIZE];
    #pragma HLS ARRAY_PARTITION variable=V dim=0 type=complete

    // Load input matrix and initialize V to identity
    LOAD_MATRIX_LOOP_I: for (int i = 0; i < MATRIX_SIZE; i++) {
        LOAD_MATRIX_LOOP_J: for (int j = 0; j < MATRIX_SIZE; j++) {
            #pragma HLS PIPELINE II=1
            int idx = i * MATRIX_SIZE + j;
            A[i][j].re = int_to_fixed(matrix_real_in[idx]);
            A[i][j].im = int_to_fixed(matrix_imag_in[idx]);

            // Initialize V to identity
            if (i == j) {
                V[i][j].re = 1.0;
                V[i][j].im = 0.0;
            } else {
                V[i][j].re = 0.0;
                V[i][j].im = 0.0;
            }
        }
    }

    ap_uint<32> cycle_count = 0;

    // Jacobi iteration loop
    JACOBI_ITERATION: for (int z = 0; z < MAX_ITERATIONS; z++) {
        // Find maximum off-diagonal element
        fixed_t off_diag_max = 0;
        int p = 0, q = 1;

        FIND_MAX_I: for (int i = 0; i < MATRIX_SIZE; i++) {
            FIND_MAX_J: for (int j = i + 1; j < MATRIX_SIZE; j++) {
                #pragma HLS PIPELINE II=1
                fixed_t abs_aij = complex_abs(A[i][j]);
                if (abs_aij > off_diag_max) {
                    off_diag_max = abs_aij;
                    p = i;
                    q = j;
                }
            }
        }

        cycle_count += MATRIX_SIZE * (MATRIX_SIZE - 1) / 2;

        // Check convergence
        if (off_diag_max < CONVERGENCE_THRESHOLD) {
            iter_count = z;
            break;
        }

        // Extract pivot elements
        complex_t a_pp = A[p][p];
        complex_t a_qq = A[q][q];
        complex_t a_pq = A[p][q];

        // Compute rotation angles
        // theta = 0.5 * arctan(2 * |a_pq| / (a_pp - a_qq))
        fixed_t abs_apq = complex_abs(a_pq);
        fixed_t diff = a_pp.re - a_qq.re;  // Diagonal elements are real for Hermitian

        fixed_t theta;
        if (hls::abs(diff) < fixed_t(0.0001)) {
            // Avoid division by zero
            theta = fixed_t(0.785398163);  // pi/4 in radians
        } else {
            fixed_t ratio = (2 * abs_apq) / diff;
            theta = 0.5 * hls::atan(ratio);
        }

        fixed_t phi = -complex_angle(a_pq);

        // Compute sin/cos values
        fixed_t cos_theta = hls::cos(theta);
        fixed_t sin_theta = hls::sin(theta);

        // Compute e^(i*phi) and e^(-i*phi)
        fixed_t cos_phi = hls::cos(phi);
        fixed_t sin_phi = hls::sin(phi);
        complex_t exp_iphi(cos_phi, sin_phi);
        complex_t exp_minus_iphi(cos_phi, -sin_phi);

        // Build rotation matrix U (only non-trivial elements)
        // U[p,p] = cos(theta)
        // U[p,q] = sin(theta) * exp(-i*phi)
        // U[q,p] = sin(theta) * exp(i*phi)
        // U[q,q] = -cos(theta)  // Note: reference has this, though it may be incorrect

        complex_t U_pp(cos_theta, 0);
        complex_t U_pq = complex_t(sin_theta, 0);
        U_pq = complex_mul(U_pq, exp_minus_iphi);
        complex_t U_qp = complex_t(sin_theta, 0);
        U_qp = complex_mul(U_qp, exp_iphi);
        complex_t U_qq(-cos_theta, 0);

        // Temporary storage for row/column updates
        complex_t temp_A_row_p[MATRIX_SIZE];
        complex_t temp_A_row_q[MATRIX_SIZE];
        complex_t temp_A_col_p[MATRIX_SIZE];
        complex_t temp_A_col_q[MATRIX_SIZE];

        #pragma HLS ARRAY_PARTITION variable=temp_A_row_p type=complete
        #pragma HLS ARRAY_PARTITION variable=temp_A_row_q type=complete
        #pragma HLS ARRAY_PARTITION variable=temp_A_col_p type=complete
        #pragma HLS ARRAY_PARTITION variable=temp_A_col_q type=complete

        // Apply transformation A = U^H @ A @ U
        // Step 1: Compute A' = A @ U (right multiplication)
        // Only columns p and q are affected
        UPDATE_A_RIGHT: for (int i = 0; i < MATRIX_SIZE; i++) {
            #pragma HLS PIPELINE II=1
            complex_t a_ip = A[i][p];
            complex_t a_iq = A[i][q];

            // new A[i,p] = a_ip * U[p,p] + a_iq * U[q,p]
            temp_A_col_p[i] = complex_add(
                complex_mul(a_ip, U_pp),
                complex_mul(a_iq, U_qp)
            );

            // new A[i,q] = a_ip * U[p,q] + a_iq * U[q,q]
            temp_A_col_q[i] = complex_add(
                complex_mul(a_ip, U_pq),
                complex_mul(a_iq, U_qq)
            );
        }

        // Write back columns
        UPDATE_A_WRITE_COL: for (int i = 0; i < MATRIX_SIZE; i++) {
            #pragma HLS UNROLL
            A[i][p] = temp_A_col_p[i];
            A[i][q] = temp_A_col_q[i];
        }

        cycle_count += MATRIX_SIZE * 2;

        // Step 2: Compute A = U^H @ A' (left multiplication)
        // Only rows p and q are affected
        UPDATE_A_LEFT: for (int j = 0; j < MATRIX_SIZE; j++) {
            #pragma HLS PIPELINE II=1
            complex_t a_pj = A[p][j];
            complex_t a_qj = A[q][j];

            // new A[p,j] = conj(U[p,p]) * a_pj + conj(U[p,q]) * a_qj
            temp_A_row_p[j] = complex_add(
                complex_mul(complex_conj(U_pp), a_pj),
                complex_mul(complex_conj(U_pq), a_qj)
            );

            // new A[q,j] = conj(U[q,p]) * a_pj + conj(U[q,q]) * a_qj
            temp_A_row_q[j] = complex_add(
                complex_mul(complex_conj(U_qp), a_pj),
                complex_mul(complex_conj(U_qq), a_qj)
            );
        }

        // Write back rows
        UPDATE_A_WRITE_ROW: for (int j = 0; j < MATRIX_SIZE; j++) {
            #pragma HLS UNROLL
            A[p][j] = temp_A_row_p[j];
            A[q][j] = temp_A_row_q[j];
        }

        // Explicitly zero out the off-diagonal elements
        A[p][q].re = 0;
        A[p][q].im = 0;
        A[q][p].re = 0;
        A[q][p].im = 0;

        cycle_count += MATRIX_SIZE * 2;

        // Update eigenvector matrix V = V @ U
        // Only columns p and q are affected
        complex_t temp_V_col_p[MATRIX_SIZE];
        complex_t temp_V_col_q[MATRIX_SIZE];
        #pragma HLS ARRAY_PARTITION variable=temp_V_col_p type=complete
        #pragma HLS ARRAY_PARTITION variable=temp_V_col_q type=complete

        UPDATE_V: for (int i = 0; i < MATRIX_SIZE; i++) {
            #pragma HLS PIPELINE II=1
            complex_t v_ip = V[i][p];
            complex_t v_iq = V[i][q];

            // new V[i,p] = v_ip * U[p,p] + v_iq * U[q,p]
            temp_V_col_p[i] = complex_add(
                complex_mul(v_ip, U_pp),
                complex_mul(v_iq, U_qp)
            );

            // new V[i,q] = v_ip * U[p,q] + v_iq * U[q,q]
            temp_V_col_q[i] = complex_add(
                complex_mul(v_ip, U_pq),
                complex_mul(v_iq, U_qq)
            );
        }

        // Write back columns
        UPDATE_V_WRITE: for (int i = 0; i < MATRIX_SIZE; i++) {
            #pragma HLS UNROLL
            V[i][p] = temp_V_col_p[i];
            V[i][q] = temp_V_col_q[i];
        }

        cycle_count += MATRIX_SIZE * 2;

        // Update iteration count
        iter_count = z + 1;
    }

    // Extract eigenvalues (diagonal of A)
    EXTRACT_EIGENVALUES: for (int i = 0; i < MATRIX_SIZE; i++) {
        #pragma HLS PIPELINE II=1
        eigenvalues_real_out[i] = fixed_to_int(A[i][i].re);
    }

    // Write eigenvectors
    WRITE_EIGENVECTORS_I: for (int i = 0; i < MATRIX_SIZE; i++) {
        WRITE_EIGENVECTORS_J: for (int j = 0; j < MATRIX_SIZE; j++) {
            #pragma HLS PIPELINE II=1
            int idx = i * MATRIX_SIZE + j;
            eigenvectors_real_out[idx] = fixed_to_int(V[i][j].re);
            eigenvectors_imag_out[idx] = fixed_to_int(V[i][j].im);
        }
    }

    cycles = cycle_count;
}

#include "kernel.h"
#include <iostream>
#include <fstream>
#include <iomanip>
#include <cstdlib>
#include <cmath>

using namespace std;

int main() {
    // Allocate input/output arrays
    ap_int<TOTAL_BITS> matrix_real_in[MATRIX_SIZE * MATRIX_SIZE];
    ap_int<TOTAL_BITS> matrix_imag_in[MATRIX_SIZE * MATRIX_SIZE];
    ap_int<TOTAL_BITS> eigenvalues_real_out[MATRIX_SIZE];
    ap_int<TOTAL_BITS> eigenvectors_real_out[MATRIX_SIZE * MATRIX_SIZE];
    ap_int<TOTAL_BITS> eigenvectors_imag_out[MATRIX_SIZE * MATRIX_SIZE];
    ap_uint<12> iter_count = 0;
    ap_uint<32> cycles = 0;

    // Read reference inputs from file
    ifstream infile("../reference_inputs.txt");
    if (!infile.is_open()) {
        cerr << "ERROR: Could not open ../reference_inputs.txt" << endl;
        return 1;
    }

    cout << "Reading input matrix from reference_inputs.txt..." << endl;

    int line_num;
    long long re_val, im_val;
    char separator;
    int count = 0;

    while (infile >> line_num >> separator >> re_val >> im_val) {
        if (count >= MATRIX_SIZE * MATRIX_SIZE) {
            cerr << "WARNING: More than " << MATRIX_SIZE * MATRIX_SIZE 
                 << " elements in input file" << endl;
            break;
        }

        matrix_real_in[count] = re_val;
        matrix_imag_in[count] = im_val;
        count++;
    }
    infile.close();

    if (count != MATRIX_SIZE * MATRIX_SIZE) {
        cerr << "ERROR: Expected " << MATRIX_SIZE * MATRIX_SIZE 
             << " elements, got " << count << endl;
        return 1;
    }

    cout << "Input matrix loaded successfully (" << count << " elements)" << endl;

    // Print input matrix (first few elements)
    cout << "\nFirst few input elements:" << endl;
    for (int i = 0; i < min(5, MATRIX_SIZE); i++) {
        for (int j = 0; j < min(5, MATRIX_SIZE); j++) {
            int idx = i * MATRIX_SIZE + j;
            cout << "A[" << i << "," << j << "] = " 
                 << matrix_real_in[idx].to_int64() << " + " 
                 << matrix_imag_in[idx].to_int64() << "i" << endl;
        }
    }

    // Run the kernel
    cout << "\nRunning kernel_top..." << endl;
    kernel_top(
        matrix_real_in,
        matrix_imag_in,
        eigenvalues_real_out,
        eigenvectors_real_out,
        eigenvectors_imag_out,
        iter_count,
        cycles
    );

    cout << "Kernel completed!" << endl;
    cout << "Iterations: " << iter_count.to_uint() << endl;
    cout << "Cycles: " << cycles.to_uint() << endl;

    // Create sim directory if it doesn't exist
    system("mkdir -p ../sim");

    // Write diagonal outputs (eigenvalues) to sim_diag_out.txt
    ofstream diag_out("../sim/sim_diag_out.txt");
    if (!diag_out.is_open()) {
        cerr << "ERROR: Could not open ../sim/sim_diag_out.txt for writing" << endl;
        return 1;
    }

    cout << "\nEigenvalues (diagonal):" << endl;
    for (int i = 0; i < MATRIX_SIZE; i++) {
        long long re_out = eigenvalues_real_out[i].to_int64();
        // Eigenvalues of Hermitian matrices are real, so imaginary part is 0
        diag_out << setw(4) << (i + 1) << "|" << re_out << " 0" << endl;
        cout << "  λ[" << i << "] = " << re_out << endl;
    }
    diag_out.close();
    cout << "Wrote eigenvalues to sim/sim_diag_out.txt" << endl;

    // Write metadata
    ofstream meta_out("../sim/sim_meta.txt");
    if (!meta_out.is_open()) {
        cerr << "ERROR: Could not open ../sim/sim_meta.txt for writing" << endl;
        return 1;
    }

    meta_out << "iter_count " << iter_count.to_uint() << endl;
    meta_out << "cycles " << cycles.to_uint() << endl;
    meta_out.close();
    cout << "Wrote metadata to sim/sim_meta.txt" << endl;

    // Optional: Write eigenvectors to a separate file for debugging
    ofstream vec_out("../sim/sim_eigenvectors.txt");
    if (vec_out.is_open()) {
        vec_out << "# Eigenvectors (column-major format)" << endl;
        for (int i = 0; i < MATRIX_SIZE; i++) {
            for (int j = 0; j < MATRIX_SIZE; j++) {
                int idx = i * MATRIX_SIZE + j;
                long long re_out = eigenvectors_real_out[idx].to_int64();
                long long im_out = eigenvectors_imag_out[idx].to_int64();
                vec_out << setw(4) << (idx + 1) << "|" 
                       << re_out << " " << im_out << endl;
            }
        }
        vec_out.close();
        cout << "Wrote eigenvectors to sim/sim_eigenvectors.txt (for debugging)" << endl;
    }

    // Verification summary
    cout << "\n========================================" << endl;
    cout << "TESTBENCH SUMMARY" << endl;
    cout << "========================================" << endl;
    cout << "Matrix size: " << MATRIX_SIZE << "x" << MATRIX_SIZE << endl;
    cout << "Iterations: " << iter_count.to_uint() << " (max: " << MAX_ITERATIONS << ")" << endl;
    cout << "Cycles: " << cycles.to_uint() << endl;
    cout << "Fixed-point format: Q" << TOTAL_BITS << "." << FRAC_BITS << endl;

    if (iter_count.to_uint() >= MAX_ITERATIONS) {
        cout << "\nWARNING: Maximum iterations reached without convergence!" << endl;
    } else {
        cout << "\nSUCCESS: Algorithm converged" << endl;
    }

    cout << "========================================" << endl;

    return 0;
}
